using System;

public class Thermostat
{
    private double currentTemp = 20;

    public double CurrentTemp
    {
        get => currentTemp;
        private set
        {
            currentTemp = Math.Round(value, 1);
        }
    }

    public void Increase(double amount) => CurrentTemp += amount;
    public void Decrease(double amount) => CurrentTemp -= amount;
}

class Program
{
    static void Main()
    {
        var t = new Thermostat();
        Console.WriteLine($"Temp: {t.CurrentTemp}C");
        t.Increase(5);
        Console.WriteLine($"After increase: {t.CurrentTemp}C");
    }
}
